from flask import Flask, request, redirect, url_for, render_template, session, flash
import secrets
import hashlib
import time
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Mock user database
users = {
    'admin': {
        'password': hashlib.sha256('password123'.encode()).hexdigest(),
        'mfa_secret': 'SECRET1234567890'
    }
}

# Mock MFA token store
mfa_tokens = {}

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        
        if username in users:
            stored_password = users[username]['password']
            if hashlib.sha256(password.encode()).hexdigest() == stored_password:
                # Generate and store MFA token
                mfa_token = secrets.token_urlsafe(32)
                mfa_tokens[mfa_token] = {
                    'username': username,
                    'timestamp': time.time()
                }
                
                # Store session
                session['user_id'] = username
                session['mfa_token'] = mfa_token
                
                return redirect(url_for('verify_mfa'))
            else:
                flash('Invalid credentials')
        else:
            flash('Invalid credentials')
    
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'mfa_token' not in session:
        return redirect(url_for('login'))
    
    # Check if MFA token is valid
    mfa_token = session['mfa_token']
    if mfa_token not in mfa_tokens:
        return redirect(url_for('login'))
    
    # Check if token has expired (10 minutes)
    if time.time() - mfa_tokens[mfa_token]['timestamp'] > 600:
        del mfa_tokens[mfa_token]
        session.pop('mfa_token', None)
        return redirect(url_for('login'))
    
    if request.method == 'POST':
        mfa_code = request.form['mfa_code']
        # Simple MFA verification (in real app, use proper TOTP)
        if mfa_code == '123456':  # Mock MFA code
            # MFA verification successful
            session['mfa_verified'] = True
            del mfa_tokens[mfa_token]
            session.pop('mfa_token', None)
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid MFA code')
    
    return render_template('verify_mfa.html')

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session or 'mfa_verified' not in session:
        return redirect(url_for('login'))
    
    return f"Welcome {session['user_id']}! This is your protected dashboard."

# Background MFA verification
@app.before_request
def check_mfa():
    if request.endpoint and request.endpoint != 'verify_mfa' and request.endpoint != 'login':
        if 'user_id' in session and 'mfa_verified' not in session:
            return redirect(url_for('verify_mfa'))

if __name__ == '__main__':
    app.run(debug=True)